  `zbst_created` int(14) NOT NULL,
  `zbst_lastupdated` int(14) NOT NULL,
  PRIMARY KEY (`ID`),
  KEY `status` (`zbst_status`),
  KEY `ref` (`zbst_ref`),
  KEY `transtype` (`zbst_type`),
  KEY `transorigin` (`zbst_origin`),
