  KEY `date` (`zbst_date`),
  KEY `title` (`zbst_title`),
  KEY `created` (`zbst_created`)
) ENGINE=InnoDB AUTO_INCREMENT=29 DEFAULT CHARSET=utf8mb3 COLLATE=utf8mb3_general_ci;
